// Load the upload queue manifest (committed at
// docs/video-library/youtube/upload-queue-manifest.json).
// In production, point this read at the deployed copy or fetch it from the
// repo / a Google Sheet. Here we keep it explicit and side-effect free.
//
// DO NOT hard-code Drive/YouTube URLs. The manifest is the single source of
// truth for what has and has not been uploaded.
const fs = require('fs');
const MANIFEST_PATH = $env.LF_UPLOAD_QUEUE_PATH || '/data/upload-queue-manifest.json';
let manifest;
try {
  manifest = JSON.parse(fs.readFileSync(MANIFEST_PATH, 'utf8'));
} catch (e) {
  throw new Error('Could not read upload queue manifest at ' + MANIFEST_PATH + ': ' + e.message);
}
const rows = Array.isArray(manifest.queue) ? manifest.queue : [];
return rows.map((r) => ({ json: r }));

// SUCCESS branch — build the status patch for this clip.
// Records the real YouTube id/url returned by the upload node. Never
// fabricates a URL: if the upload node did not return an id, this is treated
// as a failure upstream.
return items.map((item) => {
  const j = item.json;
  const videoId = j.id || j.videoId || (j.snippet && j.resourceId && j.resourceId.videoId) || '';
  return {
    json: {
      clipId: j.clipId,
      rowId: j.rowId,
      queueStatus: videoId ? 'uploaded' : 'pending',
      youtubeVideoId: videoId || null,
      youtubeVideoUrl: videoId ? ('https://www.youtube.com/watch?v=' + videoId) : null,
      youtubeEmbedUrl: videoId ? ('https://www.youtube.com/embed/' + videoId) : null,
      privacyStatus: 'unlisted',
      uploadedAt: new Date().toISOString(),
      attempts: (j.attempts || 0) + 1,
      lastAttemptAt: new Date().toISOString(),
      errorMessage: null
    }
  };
});

// FAILURE branch — increment attempts and decide retry vs. needs_review.
// Up to 3 attempts; after that the clip is flagged needs_review (no infinite
// loops, no quota waste). Tomorrow's 8 AM run naturally retries 'pending' items.
return items.map((item) => {
  const j = item.json;
  const attempts = (j.attempts || 0) + 1;
  const maxAttempts = 3;
  const exhausted = attempts >= maxAttempts;
  return {
    json: {
      clipId: j.clipId,
      rowId: j.rowId,
      queueStatus: exhausted ? 'needs_review' : 'pending',
      attempts,
      lastAttemptAt: new Date().toISOString(),
      errorMessage: String(j.error || 'unknown upload error'),
      youtubeVideoId: null,
      youtubeVideoUrl: null,
      youtubeEmbedUrl: null
    }
  };
});

// REPORT — summarize the run for a human. This is a DRAFT: it only builds a
// plain summary object and returns it. It does NOT send email / chat / SMS
// (those require Jeremy's approval). Wire a notification node here later if
// desired.
const all = $input.all().map((i) => i.json);
const uploaded = all.filter((r) => r.queueStatus === 'uploaded');
const retrying = all.filter((r) => r.queueStatus === 'pending' && r.errorMessage);
const needsReview = all.filter((r) => r.queueStatus === 'needs_review');
return [{
  json: {
    runAt: new Date().toISOString(),
    batchSize: all.length,
    uploadedCount: uploaded.length,
    retryingCount: retrying.length,
    needsReviewCount: needsReview.length,
    uploaded: uploaded.map((r) => ({ clipId: r.clipId, youtubeVideoId: r.youtubeVideoId })),
    needsReview: needsReview.map((r) => ({ clipId: r.clipId, errorMessage: r.errorMessage })),
    note: 'DRAFT report node — no outbound message sent.'
  }
}];
